import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface CurrencyPair {
  baseCurrency: string;
  targetCurrency: string;
  currentRate: number;
  lastUpdated: string;
}

interface WeeklyTrend {
  date: string;
  rate: number;
}

interface CurrencyData {
  currencyPair: CurrencyPair;
  weeklyTrend: WeeklyTrend[];
}

export default function Widget() {
  const currencyData = response.data as CurrencyData;
  const { currencyPair, weeklyTrend } = currencyData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#F5F7FA' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              {currencyPair.baseCurrency}/{currencyPair.targetCurrency}
            </Typography>
            <Typography variant="h3" fontWeight={300} sx={{ my: 0.5 }}>
              {currencyPair.currentRate.toFixed(3)}
            </Typography>
            <Typography variant="body1" color="text.secondary">
              Last Updated: {new Date(currencyPair.lastUpdated).toLocaleString()}
            </Typography>
          </Box>

          <LineChart
            height={120}
            series={[
              {
                data: weeklyTrend.map((trend) => trend.rate),
                color: '#4682B4',
                curve: 'natural',
                showMark: false,
              },
            ]}
            xAxis={[{ data: weeklyTrend.map((trend) => trend.date), hide: true }]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 2,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
